CREATE TABLE kanban_boards (id TEXT PRIMARY KEY, workspaceId TEXT NOT NULL, name TEXT NOT NULL, isDefault INTEGER NOT NULL DEFAULT 0, createdAt TEXT NOT NULL, updatedAt TEXT NOT NULL, UNIQUE(workspaceId, name));
CREATE UNIQUE INDEX idx_kanban_default_board ON kanban_boards(workspaceId) WHERE isDefault = 1;
CREATE TABLE kanban_stages (id TEXT PRIMARY KEY, boardId TEXT NOT NULL REFERENCES kanban_boards(id), key TEXT NOT NULL, name TEXT NOT NULL, position REAL NOT NULL, isTerminal INTEGER NOT NULL DEFAULT 0, isArchivedStage INTEGER NOT NULL DEFAULT 0, createdAt TEXT NOT NULL, updatedAt TEXT NOT NULL, UNIQUE(boardId, key), UNIQUE(boardId, position));
CREATE TABLE conversation_kanban_state (workspaceId TEXT NOT NULL, conversationId TEXT NOT NULL, boardId TEXT NOT NULL REFERENCES kanban_boards(id), stageId TEXT NOT NULL REFERENCES kanban_stages(id), position REAL NOT NULL, manualOverride INTEGER NOT NULL DEFAULT 0, lastTransitionSource TEXT NOT NULL, lastTransitionBy TEXT, lastTransitionAt TEXT NOT NULL, createdAt TEXT NOT NULL, updatedAt TEXT NOT NULL, PRIMARY KEY(conversationId, boardId), FOREIGN KEY(workspaceId, conversationId) REFERENCES conversations(workspaceId, id));
CREATE INDEX idx_kanban_state_stage ON conversation_kanban_state(boardId, stageId, position);
CREATE TABLE conversation_kanban_events (id TEXT PRIMARY KEY, workspaceId TEXT NOT NULL, conversationId TEXT NOT NULL, boardId TEXT NOT NULL, fromStageId TEXT, toStageId TEXT NOT NULL, source TEXT NOT NULL, actorId TEXT, metadataSafe TEXT NOT NULL DEFAULT '{}', createdAt TEXT NOT NULL);
CREATE INDEX idx_kanban_events_conversation ON conversation_kanban_events(workspaceId, conversationId, createdAt DESC);
